import{_ as e,o as a,c as n,a2 as o}from"./chunks/framework.Bix3-HpO.js";const d=JSON.parse('{"title":"Translating Spinoko Theme","description":"Translating Spinoko Theme","frontmatter":{"title":"Translating Spinoko Theme","description":"Translating Spinoko Theme","weight":190,"extra":{"order":190},"head":[["link",{"rel":"canonical","href":"https://docs.dinomatic.com/docs/spinoko/translation"}],["meta",{"property":"og:url","content":"https://docs.dinomatic.com/docs/spinoko/translation"}],["meta",{"property":"og:title","content":"Translating Spinoko Theme"}],["meta",{"property":"og:description","content":"Translating Spinoko Theme"}],["meta",{"name":"twitter:title","content":"Translating Spinoko Theme"}],["meta",{"name":"twitter:description","content":"Translating Spinoko Theme"}]]},"headers":[],"relativePath":"docs/spinoko/translation.md","filePath":"docs/spinoko/translation.md"}'),i={name:"docs/spinoko/translation.md"};function r(s,t,l,u,h,p){return a(),n("div",null,[...t[0]||(t[0]=[o('<h1 id="translating-the-theme" tabindex="-1">Translating The Theme <a class="header-anchor" href="#translating-the-theme" aria-label="Permalink to &quot;Translating The Theme&quot;">​</a></h1><p>Spinoko is ready to be translated into any other language or even be used on a multilingual website.</p><h3 id="single-language" tabindex="-1">Single Language <a class="header-anchor" href="#single-language" aria-label="Permalink to &quot;Single Language&quot;">​</a></h3><p>By default everything in Spinoko is in English, and you can change that easily. If you&#39;re website has a single language, you don&#39;t need any additional plugins to translate the theme. All the text strings used in Spinoko can be edited, translated into any other language, in <a href="/docs/spinoko/customizations#strings">Customizer → Strings</a>.</p><h3 id="multilingual" tabindex="-1">Multilingual <a class="header-anchor" href="#multilingual" aria-label="Permalink to &quot;Multilingual&quot;">​</a></h3><p>Spinoko comes with 100% multilingual support, it can be used to build multilingual websites. The main plugins such as WPML, Polylang can be used with Spinoko, and depending on the translation plugin you use, it may be a little different.</p><h4 id="wpml" tabindex="-1">WPML <a class="header-anchor" href="#wpml" aria-label="Permalink to &quot;WPML&quot;">​</a></h4><p><a href="https://wpml.org" target="_blank" rel="noreferrer">WPML</a> is one of the most popular and powerful multilingual plugins for WordPress. It&#39;s been around for a long time and has great support in case you need it. Using WPML with Spinoko theme is quite straightforward:</p><ul><li>I assume you already have Spinoko theme installed and activated.</li><li>Install the WPML plugins - <em>WPML Multilingual CMS</em> and <em>WPML String Translation</em> - and activate them</li><li>Follow the WPML&#39;s setup wizard which will guide you through the whole process of setting up the plugin including languages and more</li></ul><p>You can translate your posts and pages, as well as casinos and games as usual. If you&#39;re not familiar with how WPML works, I&#39;d recommend you start here - <a href="https://wpml.org/documentation/getting-started-guide" target="_blank" rel="noreferrer">Getting Started with WPML</a>.</p><p>To translate other strings in Spinoko theme, you need to visit <strong>WPML</strong> → <strong>String Translation</strong> in your dashboard, and you&#39;ll find them all there. There are 2 groups of strings in Spinoko with the following text domains:</p><ul><li>&quot;spinoko&quot; - these are the strings that are visible on the front-end of the website</li><li>&quot;spinoko-admin&quot; - these strings are only visible in the dashboard of your website.</li></ul><p>To make it easier for you and help you move faster and save some time, I separated the strings. This way you can start with just &quot;spinoko&quot; strings, and come back to &quot;spinoko-admin&quot; when already done with the front-end.</p><p>If you need further assistance with WPML, please visit their <a href="https://wpml.org/forums/forum/english-support" target="_blank" rel="noreferrer">support forum</a>.</p><h4 id="polylang" tabindex="-1">Polylang <a class="header-anchor" href="#polylang" aria-label="Permalink to &quot;Polylang&quot;">​</a></h4><p>Polylang is another popular WP multilingual plugin, and it can be used along with Spinoko to create multilingual WordPress websites. After installing and activating the plugin, going through the setup steps, you can translate all the post types (posts, pages, casinos, games) as usual. If you&#39;re not familiar with Polylang, I&#39;d suggest you check out their &quot;<a href="https://polylang.pro/doc-category/getting-started/" target="_blank" rel="noreferrer">Getting Started</a>&quot; series of articles.</p><p>If you need further assistance with Polylang, please visit their <a href="https://polylang.pro/doc/" target="_blank" rel="noreferrer">support page</a> where you can also submit a support request.</p><h3 id="rtl-and-ttb" tabindex="-1">RTL and TTB <a class="header-anchor" href="#rtl-and-ttb" aria-label="Permalink to &quot;RTL and TTB&quot;">​</a></h3><p>Spinoko can be translated into any language, it has built-in support for right-to-left (RTL), as well as top-to-bottom (TTB) languages.</p>',19)])])}const m=e(i,[["render",r]]);export{d as __pageData,m as default};
